            "title": "Memória litúrgica do calendário católico",
            "feastDay": "1 de junho",
            "image": "https://www.vaticannews.va/content/dam/vaticannews/santi/20171113_SPC_Elvira%20Ortmann_GIUSTINO.jpg/_jcr_content/renditions/cq5dam.thumbnail.cropped.1500.844.jpeg",
